module counter_8bit(clk, reset, enable, obf_Q);
     input clk;
     input reset;
     input enable;
     output [7:0] obf_Q;

     reg [7:0] obf_Q;

     always @(posedge clk or posedge reset) begin
         if (reset)
             obf_Q <= 8'b0;
         else if (enable)
             obf_Q <= obf_Q + 1;
     end
endmodule
